def solve(bun_value, hemoglobin_value, sex, sbp_value, pulse_above_100, melena_present, syncope_present, liver_disease_history, cardiac_failure_present):
    # Step 1: compute_bun_score - Calculate the BUN score based on the patient's Blood Urea Nitrogen value.
    if bun_value < 18.2:
        bun_score = 0
    elif 18.2 <= bun_value <= 22.3:
        bun_score = 2
    elif 22.4 <= bun_value <= 28:
        bun_score = 3
    elif 28 < bun_value <= 70:
        bun_score = 4
    else:  # bun_value > 70
        bun_score = 6
    yield {
        "step_name": "compute_bun_score",
        "step_description": "Calculate the BUN score based on the patient's Blood Urea Nitrogen value.",
        "step_result": bun_score,
        "unit": None
    }

    # Step 2: compute_hemoglobin_score - Calculate the Hemoglobin score based on the patient's hemoglobin value and sex.
    if sex == 'male':
        if hemoglobin_value >= 13:
            hemoglobin_score = 0
        elif 12 < hemoglobin_value <= 13:
            hemoglobin_score = 1
        elif 10 <= hemoglobin_value <= 12:
            hemoglobin_score = 3
        else:  # hemoglobin_value < 10
            hemoglobin_score = 6
    else:  # sex == 'female'
        if hemoglobin_value >= 12:
            hemoglobin_score = 0
        elif 10 <= hemoglobin_value < 12:
            hemoglobin_score = 1
        else:  # hemoglobin_value < 10
            hemoglobin_score = 6
    yield {
        "step_name": "compute_hemoglobin_score",
        "step_description": "Calculate the Hemoglobin score based on the patient's hemoglobin value and sex.",
        "step_result": hemoglobin_score,
        "unit": None
    }

    # Step 3: compute_sbp_score - Calculate the Systolic Blood Pressure score.
    if sbp_value >= 110:
        sbp_score = 0
    elif 100 <= sbp_value <= 109:
        sbp_score = 1
    elif 90 <= sbp_value <= 99:
        sbp_score = 2
    else:  # sbp_value < 90
        sbp_score = 3
    yield {
        "step_name": "compute_sbp_score",
        "step_description": "Calculate the Systolic Blood Pressure score.",
        "step_result": sbp_score,
        "unit": None
    }

    # Step 4: compute_boolean_scores - Calculate the scores for all boolean-type criteria.
    pulse_score = 1 if pulse_above_100 else 0
    melena_score = 1 if melena_present else 0
    syncope_score = 2 if syncope_present else 0
    liver_disease_score = 2 if liver_disease_history else 0
    cardiac_failure_score = 2 if cardiac_failure_present else 0
    yield {
        "step_name": "compute_boolean_scores",
        "step_description": "Calculate the scores for all boolean-type criteria: Pulse >=100, Melena, Syncope, Liver disease history, and Cardiac failure.",
        "step_result": {
            "pulse_score": pulse_score,
            "melena_score": melena_score,
            "syncope_score": syncope_score,
            "liver_disease_score": liver_disease_score,
            "cardiac_failure_score": cardiac_failure_score
        },
        "unit": None
    }

    # Step 5: compute_total_gbs - Sum all individual criterion scores to produce the total Glasgow-Blatchford Score.
    total_score = bun_score + hemoglobin_score + sbp_score + pulse_score + melena_score + syncope_score + liver_disease_score + cardiac_failure_score
    yield {
        "step_name": "compute_total_gbs",
        "step_description": "Sum all individual criterion scores to produce the total Glasgow-Blatchford Score.",
        "step_result": total_score,
        "unit": None
    }

    return total_score
